import React, { useState } from 'react';

// Define EXIF fields with prefixes for JSONPath queries
const exifFields = {
    Image: ["ImageWidth", "ImageHeight", "Make", "Model", "DateTimeOriginal"],
    Photo: ["FocalLength", "ApertureValue", "ISO"],
    GPSInfo: ["GPSLatitude", "GPSLongitude"]
};

const ExifForm = ({ axiosInstance, imagePath }) => {
    const [selectedFields, setSelectedFields] = useState([]);
    const [checkAll, setCheckAll] = useState(false);

    // Handle checkbox toggle
    const handleCheckboxChange = (prefix, field) => {
        const fullField = `${prefix}.${field}`;
        setSelectedFields((prev) =>
            prev.includes(fullField)
                ? prev.filter((item) => item !== fullField)
                : [...prev, fullField]
        );
    };

    // Handle "Check All" toggle
    const handleCheckAll = () => {
        if (checkAll) {
            setSelectedFields([]);
        } else {
            const allFields = Object.entries(exifFields).flatMap(([prefix, fields]) =>
                fields.map((field) => `${prefix}.${field}`)
            );
            setSelectedFields(allFields);
        }
        setCheckAll(!checkAll);
    };

    // Handle form submission
    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            const jsonPathQuery = selectedFields.map((field) => `$..${field}`);
            const response = await axiosInstance.post(
                '/query',
                {
                    imagePath,
                    query: jsonPathQuery
                },
                {
                    headers: {
                        'Content-Type': 'application/json'
                    }
                }
            );
            console.log('Response:', response.data);
        } catch (error) {
            console.error('Error submitting form:', error);
        }
    };

    return (
        <form
            onSubmit={handleSubmit}
            style={{
                padding: '20px',
                border: '1px solid #ccc',
                borderRadius: '5px',
                maxWidth: '600px',
                margin: 'auto',
                backgroundColor: '#f9f9f9'
            }}
        >
            <h3 style={{ textAlign: 'center', color: '#333' }}>
                Select EXIF Fields to Query
            </h3>
            <div style={{ marginBottom: '10px' }}>
                <label style={{ display: 'flex', alignItems: 'center' }}>
                    <input
                        type="checkbox"
                        checked={checkAll}
                        onChange={handleCheckAll}
                        style={{ marginRight: '10px' }}
                    />
                    Check All
                </label>
            </div>
            <div style={{ display: 'flex', gap: '10px', justifyContent: 'space-between' }}>
                {Object.entries(exifFields).map(([prefix, fields]) => (
                    <div
                        key={prefix}
                        style={{
                            flex: '1',
                            border: '1px solid #ddd',
                            padding: '10px',
                            borderRadius: '5px',
                            backgroundColor: '#fff'
                        }}
                    >
                        <h4 style={{ textAlign: 'center', marginBottom: '10px' }}>{prefix}</h4>
                        {fields.map((field) => (
                            <label
                                key={field}
                                style={{
                                    display: 'flex',
                                    alignItems: 'center',
                                    marginBottom: '5px'
                                }}
                            >
                                <input
                                    type="checkbox"
                                    value={`${prefix}.${field}`}
                                    checked={selectedFields.includes(`${prefix}.${field}`)}
                                    onChange={() => handleCheckboxChange(prefix, field)}
                                    style={{ marginRight: '10px' }}
                                />
                                {field}
                            </label>
                        ))}
                    </div>
                ))}
            </div>
            <button
                type="submit"
                style={{
                    display: 'block',
                    width: '100%',
                    padding: '10px',
                    backgroundColor: '#007bff',
                    color: '#fff',
                    border: 'none',
                    borderRadius: '5px',
                    cursor: 'pointer',
                    marginTop: '20px'
                }}
            >
                Submit Query
            </button>
        </form>
    );
};

export default ExifForm;
